#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Azure Service Principal with Client Secret
 *
 * Description: Use Azure Service Principal for automation and CI/CD on Azure.
 *
 * Prerequisites:
 * - Azure Service Principal created
 * - Service Principal has permissions to Databricks workspace
 * - Client ID, client secret, and tenant ID
 *
 * Setup:
 * 1. Create service principal: az ad sp create-for-rbac --name <name>
 * 2. Grant service principal permissions to Databricks workspace
 * 3. Copy client ID, client secret, and tenant ID
 *
 * Run:
 * ```bash
 * DATABRICKS_HOST="https://adb-<workspace-id>.<random>.azuredatabricks.net" \
 * DATABRICKS_AZURE_CLIENT_ID="<client-id>" \
 * DATABRICKS_AZURE_CLIENT_SECRET="<client-secret>" \
 * DATABRICKS_AZURE_TENANT_ID="<tenant-id>" \
 * npx ts-node examples/auth/azure-client-secret.ts
 * ```
 */

import {Config, WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    const config = new Config({
        host: process.env.DATABRICKS_HOST,
        azureClientId: process.env.DATABRICKS_AZURE_CLIENT_ID,
        azureClientSecret: process.env.DATABRICKS_AZURE_CLIENT_SECRET,
        azureTenantId: process.env.DATABRICKS_AZURE_TENANT_ID,
    });

    const client = new WorkspaceClient(config);

    try {
        const user = await client.currentUser.me();
        console.log(
            `✓ Successfully authenticated as Azure service principal: ${user.userName}`
        );
        console.log(`  User ID: ${user.id}`);

        console.log(`  Host: ${config.host}`);
        console.log(`  Azure Client ID: ${config.azureClientId}`);
        console.log(`  Azure Tenant ID: ${config.azureTenantId}`);
    } catch (error) {
        console.error("✗ Authentication failed:", error);
        console.error(
            "\nMake sure you have set the following environment variables:"
        );
        console.error("  - DATABRICKS_HOST");
        console.error("  - DATABRICKS_AZURE_CLIENT_ID");
        console.error("  - DATABRICKS_AZURE_CLIENT_SECRET");
        console.error("  - DATABRICKS_AZURE_TENANT_ID");
        process.exit(1);
    }
}

main().catch(console.error);
